class Solution {
public:
    vector<int> numsSameConsecDiff(int n, int k) {
        vector<int> res;
        for (int i = 1; i < pow(10, n); i++) {
            if (isValid(i, n, k)) {
                res.push_back(i);
            }
        }
        return res;
    }

    bool isValid(int num, int n, int k) {
        int count = 0;
        while (num > 0) {
            int digit = num % 10;
            if (count > 0 && abs(digit - (num / 10) % 10) != k) {
                return false;
            }
            count++;
            num /= 10;
        }
        return count == n;
    }
};
